    # Test 16: Compliance check marks unknown packages
    It "marks packages with no license info as UNKNOWN" {
        $deps = @(
            [PSCustomObject]@{ Name = "mystery-lib"; Version = "2.0.0" }
        )
        $mockDb = @{}
        $config = @{ Allow = @("MIT"); Deny = @("GPL-3.0") }

